import React, { useState, useEffect } from 'react';
import api from '../lib/api';

const Settings = () => {
  const [activeTab, setActiveTab] = useState('apis');
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });

  const [apiSettings, setApiSettings] = useState({
    libreNms: { enabled: false, url: '', apiKey: '', syncDevices: true, syncAlerts: true, status: 'disconnected' },
    phpIpam: { enabled: false, url: '', appId: '', appKey: '', syncSubnets: true, syncDevices: true, status: 'disconnected' }
  });

  const [users, setUsers] = useState([]);
  const [userForm, setUserForm] = useState({
    username: '', email: '', password: '', confirmPassword: '', role: 'viewer',
    syncToLibreNms: true, syncToPhpIpam: true, isActive: true
  });
  const [showUserForm, setShowUserForm] = useState(false);
  const [editingUser, setEditingUser] = useState(null);

  const [theme, setTheme] = useState({ mode: 'dark', primaryColor: 'blue', sidebarStyle: 'default', fontSize: 'medium', compactMode: false });

  const [aiSettings, setAiSettings] = useState({
    enabled: true, provider: 'openai', apiKey: '', model: 'gpt-4',
    autoAnalysis: true, storeKnowledge: true, analysisInterval: 60,
    alertThreshold: 'medium', knowledgeBase: { enabled: true, retentionDays: 365, autoLearn: true }
  });
  const [knowledgeEntries, setKnowledgeEntries] = useState([]);
  const [aiQuery, setAiQuery] = useState('');
  const [aiResponse, setAiResponse] = useState('');

  const tabs = [
    { id: 'apis', label: 'APIs Externas', icon: '🔌' },
    { id: 'users', label: 'Usuários', icon: '👥' },
    { id: 'themes', label: 'Temas', icon: '🎨' },
    { id: 'ai', label: 'Inteligência Artificial', icon: '🤖' }
  ];

  useEffect(() => { loadSettings(); loadUsers(); loadKnowledgeBase(); }, []);

  const loadSettings = async () => {
    try {
      const response = await api.get('/settings/');
      if (response.data) {
        if (response.data.apis) setApiSettings(prev => ({ ...prev, ...response.data.apis }));
        if (response.data.theme) setTheme(prev => ({ ...prev, ...response.data.theme }));
        if (response.data.ai) setAiSettings(prev => ({ ...prev, ...response.data.ai }));
      }
    } catch (error) { console.log('Using default settings'); }
  };

  const loadUsers = async () => {
    try {
      const response = await api.get('/users/');
      setUsers(response.data.results || response.data || []);
    } catch (error) {
      setUsers([{ id: 1, username: 'admin', email: 'admin@lorcgr.local', role: 'admin', isActive: true, syncedSystems: ['libreNms', 'phpIpam'] }]);
    }
  };

  const loadKnowledgeBase = async () => {
    try {
      const response = await api.get('/ai/knowledge/');
      setKnowledgeEntries(response.data.results || response.data || []);
    } catch (error) { console.log('Knowledge base empty'); }
  };

  const saveApiSettings = async () => {
    setLoading(true);
    try {
      await api.post('/settings/', { apis: apiSettings });
      setMessage({ type: 'success', text: 'Configurações de API salvas!' });
    } catch (error) { setMessage({ type: 'error', text: 'Erro ao salvar' }); }
    setLoading(false);
  };

  const testConnection = async (system) => {
    setLoading(true);
    try {
      const response = await api.post('/settings/test_connection/', { system });
      if (response.data.success) {
        setApiSettings(prev => ({ ...prev, [system]: { ...prev[system], status: 'connected' } }));
        setMessage({ type: 'success', text: 'Conexão bem sucedida!' });
      } else { setMessage({ type: 'error', text: response.data.error }); }
    } catch (error) { setMessage({ type: 'error', text: 'Erro ao testar conexão' }); }
    setLoading(false);
  };

  const syncNow = async (system) => {
    setLoading(true);
    try {
      await api.post('/settings/sync/', { system });
      setMessage({ type: 'success', text: 'Sincronização iniciada!' });
    } catch (error) { setMessage({ type: 'error', text: 'Erro na sincronização' }); }
    setLoading(false);
  };

  const handleUserSubmit = async (e) => {
    e.preventDefault();
    if (userForm.password !== userForm.confirmPassword) {
      setMessage({ type: 'error', text: 'As senhas não coincidem' }); return;
    }
    setLoading(true);
    try {
      const userData = {
        username: userForm.username, email: userForm.email, password: userForm.password,
        role: userForm.role, sync_to_librenms: userForm.syncToLibreNms,
        sync_to_phpipam: userForm.syncToPhpIpam, is_active: userForm.isActive
      };
      if (editingUser) {
        await api.patch('/users/' + editingUser.id + '/', userData);
        setMessage({ type: 'success', text: 'Usuário atualizado!' });
      } else {
        await api.post('/users/', userData);
        setMessage({ type: 'success', text: 'Usuário criado e sincronizado!' });
      }
      loadUsers(); resetUserForm();
    } catch (error) { setMessage({ type: 'error', text: error.response?.data?.detail || 'Erro ao salvar' }); }
    setLoading(false);
  };

  const resetUserForm = () => {
    setUserForm({ username: '', email: '', password: '', confirmPassword: '', role: 'viewer', syncToLibreNms: true, syncToPhpIpam: true, isActive: true });
    setShowUserForm(false); setEditingUser(null);
  };

  const editUser = (user) => {
    setUserForm({
      username: user.username, email: user.email, password: '', confirmPassword: '', role: user.role,
      syncToLibreNms: user.syncedSystems?.includes('libreNms') || false,
      syncToPhpIpam: user.syncedSystems?.includes('phpIpam') || false, isActive: user.isActive
    });
    setEditingUser(user); setShowUserForm(true);
  };

  const deleteUser = async (userId) => {
    if (!window.confirm('Excluir usuário?')) return;
    try { await api.delete('/users/' + userId + '/'); setMessage({ type: 'success', text: 'Usuário excluído!' }); loadUsers(); }
    catch (error) { setMessage({ type: 'error', text: 'Erro ao excluir' }); }
  };

  const saveThemeSettings = async () => {
    setLoading(true);
    try {
      await api.post('/settings/', { theme });
      localStorage.setItem('lorcgr-theme', JSON.stringify(theme));
      setMessage({ type: 'success', text: 'Tema salvo!' });
    } catch (error) { setMessage({ type: 'error', text: 'Erro ao salvar tema' }); }
    setLoading(false);
  };

  const saveAiSettings = async () => {
    setLoading(true);
    try { await api.post('/settings/', { ai: aiSettings }); setMessage({ type: 'success', text: 'Configurações de IA salvas!' }); }
    catch (error) { setMessage({ type: 'error', text: 'Erro ao salvar' }); }
    setLoading(false);
  };

  const askAi = async () => {
    if (!aiQuery.trim()) return;
    setLoading(true);
    try {
      const response = await api.post('/ai/query/', { question: aiQuery });
      setAiResponse(response.data.answer);
      loadKnowledgeBase();
    } catch (error) { setAiResponse('Erro ao processar consulta.'); }
    setLoading(false);
  };

  const roleLabels = { admin: 'Administrador', operator: 'Operador', viewer: 'Visualizador' };
  const roleColors = { admin: 'bg-purple-600', operator: 'bg-blue-600', viewer: 'bg-gray-600' };

  return (
    <div className="p-6">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-white">Configurações</h1>
        <p className="text-gray-400 mt-1">Gerencie as configurações do sistema LOR CGR</p>
      </div>

      {message.text && (
        <div className={'mb-4 p-4 rounded-lg ' + (message.type === 'success' ? 'bg-green-600/20 text-green-400 border border-green-600' : 'bg-red-600/20 text-red-400 border border-red-600')}>
          {message.text}
        </div>
      )}

      <div className="flex space-x-1 mb-6 bg-gray-800 rounded-lg p-1">
        {tabs.map(tab => (
          <button key={tab.id} onClick={() => setActiveTab(tab.id)}
            className={'flex items-center space-x-2 px-4 py-2 rounded-lg transition-all ' + (activeTab === tab.id ? 'bg-blue-600 text-white' : 'text-gray-400 hover:text-white hover:bg-gray-700')}>
            <span>{tab.icon}</span><span>{tab.label}</span>
          </button>
        ))}
      </div>

      {/* APIs Tab */}
      {activeTab === 'apis' && (
        <div className="space-y-6">
          <div className="bg-gray-800 rounded-lg p-6">
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center space-x-3">
                <div className="w-10 h-10 bg-blue-600 rounded-lg flex items-center justify-center"><span className="text-xl">📊</span></div>
                <div><h3 className="text-lg font-semibold text-white">LibreNMS</h3><p className="text-sm text-gray-400">Sistema de monitoramento</p></div>
              </div>
              <div className="flex items-center space-x-3">
                <span className={'px-3 py-1 rounded-full text-xs font-medium ' + (apiSettings.libreNms.status === 'connected' ? 'bg-green-600/20 text-green-400' : 'bg-red-600/20 text-red-400')}>
                  {apiSettings.libreNms.status === 'connected' ? 'Conectado' : 'Desconectado'}
                </span>
                <label className="flex items-center">
                  <input type="checkbox" checked={apiSettings.libreNms.enabled} onChange={(e) => setApiSettings(prev => ({ ...prev, libreNms: { ...prev.libreNms, enabled: e.target.checked } }))} className="w-5 h-5 rounded bg-gray-700 border-gray-600 text-blue-600" />
                  <span className="ml-2 text-gray-300">Ativar</span>
                </label>
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-1">URL</label>
                <input type="url" value={apiSettings.libreNms.url} onChange={(e) => setApiSettings(prev => ({ ...prev, libreNms: { ...prev.libreNms, url: e.target.value } }))} placeholder="https://librenms.example.com" className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500" />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-1">API Key</label>
                <input type="password" value={apiSettings.libreNms.apiKey} onChange={(e) => setApiSettings(prev => ({ ...prev, libreNms: { ...prev.libreNms, apiKey: e.target.value } }))} placeholder="••••••••" className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500" />
              </div>
            </div>
            <div className="mt-4 flex space-x-3">
              <button onClick={() => testConnection('libreNms')} disabled={loading} className="px-4 py-2 bg-gray-600 hover:bg-gray-500 text-white rounded-lg transition">Testar Conexão</button>
              <button onClick={() => syncNow('libreNms')} disabled={loading} className="px-4 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg transition">Sincronizar</button>
            </div>
          </div>

          <div className="bg-gray-800 rounded-lg p-6">
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center space-x-3">
                <div className="w-10 h-10 bg-orange-600 rounded-lg flex items-center justify-center"><span className="text-xl">🌐</span></div>
                <div><h3 className="text-lg font-semibold text-white">phpIPAM</h3><p className="text-sm text-gray-400">Gerenciamento IP</p></div>
              </div>
              <div className="flex items-center space-x-3">
                <span className={'px-3 py-1 rounded-full text-xs font-medium ' + (apiSettings.phpIpam.status === 'connected' ? 'bg-green-600/20 text-green-400' : 'bg-red-600/20 text-red-400')}>
                  {apiSettings.phpIpam.status === 'connected' ? 'Conectado' : 'Desconectado'}
                </span>
                <label className="flex items-center">
                  <input type="checkbox" checked={apiSettings.phpIpam.enabled} onChange={(e) => setApiSettings(prev => ({ ...prev, phpIpam: { ...prev.phpIpam, enabled: e.target.checked } }))} className="w-5 h-5 rounded bg-gray-700 border-gray-600 text-blue-600" />
                  <span className="ml-2 text-gray-300">Ativar</span>
                </label>
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-1">URL</label>
                <input type="url" value={apiSettings.phpIpam.url} onChange={(e) => setApiSettings(prev => ({ ...prev, phpIpam: { ...prev.phpIpam, url: e.target.value } }))} placeholder="https://phpipam.example.com" className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500" />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-1">App ID</label>
                <input type="text" value={apiSettings.phpIpam.appId} onChange={(e) => setApiSettings(prev => ({ ...prev, phpIpam: { ...prev.phpIpam, appId: e.target.value } }))} placeholder="lorcgr" className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500" />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-1">App Key</label>
                <input type="password" value={apiSettings.phpIpam.appKey} onChange={(e) => setApiSettings(prev => ({ ...prev, phpIpam: { ...prev.phpIpam, appKey: e.target.value } }))} placeholder="••••••••" className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500" />
              </div>
            </div>
            <div className="mt-4 flex space-x-3">
              <button onClick={() => testConnection('phpIpam')} disabled={loading} className="px-4 py-2 bg-gray-600 hover:bg-gray-500 text-white rounded-lg transition">Testar Conexão</button>
              <button onClick={() => syncNow('phpIpam')} disabled={loading} className="px-4 py-2 bg-orange-600 hover:bg-orange-500 text-white rounded-lg transition">Sincronizar</button>
            </div>
          </div>

          <button onClick={saveApiSettings} disabled={loading} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-lg font-medium transition">
            {loading ? 'Salvando...' : 'Salvar Configurações de API'}
          </button>
        </div>
      )}

      {/* Users Tab */}
      {activeTab === 'users' && (
        <div className="space-y-6">
          <div className="flex justify-between items-center">
            <h3 className="text-lg font-semibold text-white">Gerenciamento de Usuários</h3>
            <button onClick={() => setShowUserForm(true)} className="px-4 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg transition">+ Novo Usuário</button>
          </div>

          {showUserForm && (
            <div className="bg-gray-800 rounded-lg p-6">
              <h4 className="text-md font-semibold text-white mb-4">{editingUser ? 'Editar Usuário' : 'Novo Usuário'}</h4>
              <form onSubmit={handleUserSubmit} className="space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-1">Usuário</label>
                    <input type="text" value={userForm.username} onChange={(e) => setUserForm(prev => ({ ...prev, username: e.target.value }))} required className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500" />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-1">Email</label>
                    <input type="email" value={userForm.email} onChange={(e) => setUserForm(prev => ({ ...prev, email: e.target.value }))} required className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500" />
                  </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-1">Senha</label>
                    <input type="password" value={userForm.password} onChange={(e) => setUserForm(prev => ({ ...prev, password: e.target.value }))} required={!editingUser} className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500" />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-1">Confirmar Senha</label>
                    <input type="password" value={userForm.confirmPassword} onChange={(e) => setUserForm(prev => ({ ...prev, confirmPassword: e.target.value }))} required={!editingUser} className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500" />
                  </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-1">Função</label>
                    <select value={userForm.role} onChange={(e) => setUserForm(prev => ({ ...prev, role: e.target.value }))} className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500">
                      <option value="viewer">Visualizador</option>
                      <option value="operator">Operador</option>
                      <option value="admin">Administrador</option>
                    </select>
                  </div>
                  <div className="flex items-end">
                    <label className="flex items-center">
                      <input type="checkbox" checked={userForm.isActive} onChange={(e) => setUserForm(prev => ({ ...prev, isActive: e.target.checked }))} className="w-4 h-4 rounded bg-gray-700 border-gray-600 text-blue-600" />
                      <span className="ml-2 text-gray-300">Usuário ativo</span>
                    </label>
                  </div>
                </div>
                <div className="bg-gray-700/50 rounded-lg p-4">
                  <h5 className="text-sm font-medium text-gray-300 mb-3">Sincronização com Sistemas Externos</h5>
                  <div className="flex flex-wrap gap-6">
                    <label className="flex items-center">
                      <input type="checkbox" checked={userForm.syncToLibreNms} onChange={(e) => setUserForm(prev => ({ ...prev, syncToLibreNms: e.target.checked }))} className="w-4 h-4 rounded bg-gray-700 border-gray-600 text-blue-600" />
                      <span className="ml-2 text-gray-300">Criar no LibreNMS</span>
                    </label>
                    <label className="flex items-center">
                      <input type="checkbox" checked={userForm.syncToPhpIpam} onChange={(e) => setUserForm(prev => ({ ...prev, syncToPhpIpam: e.target.checked }))} className="w-4 h-4 rounded bg-gray-700 border-gray-600 text-blue-600" />
                      <span className="ml-2 text-gray-300">Criar no phpIPAM</span>
                    </label>
                  </div>
                </div>
                <div className="flex space-x-3">
                  <button type="submit" disabled={loading} className="px-6 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg transition">{loading ? 'Salvando...' : (editingUser ? 'Atualizar' : 'Criar Usuário')}</button>
                  <button type="button" onClick={resetUserForm} className="px-6 py-2 bg-gray-600 hover:bg-gray-500 text-white rounded-lg transition">Cancelar</button>
                </div>
              </form>
            </div>
          )}

          <div className="bg-gray-800 rounded-lg overflow-hidden">
            <table className="w-full">
              <thead className="bg-gray-700">
                <tr>
                  <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">Usuário</th>
                  <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">Email</th>
                  <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">Função</th>
                  <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">Status</th>
                  <th className="px-4 py-3 text-left text-sm font-medium text-gray-300">Sincronizado</th>
                  <th className="px-4 py-3 text-right text-sm font-medium text-gray-300">Ações</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-700">
                {users.map(user => (
                  <tr key={user.id} className="hover:bg-gray-700/50">
                    <td className="px-4 py-3 text-white">{user.username}</td>
                    <td className="px-4 py-3 text-gray-300">{user.email}</td>
                    <td className="px-4 py-3"><span className={'px-2 py-1 rounded text-xs font-medium ' + roleColors[user.role]}>{roleLabels[user.role]}</span></td>
                    <td className="px-4 py-3"><span className={'px-2 py-1 rounded text-xs font-medium ' + (user.isActive ? 'bg-green-600/20 text-green-400' : 'bg-red-600/20 text-red-400')}>{user.isActive ? 'Ativo' : 'Inativo'}</span></td>
                    <td className="px-4 py-3">
                      <div className="flex space-x-1">
                        {user.syncedSystems && user.syncedSystems.map(s => <span key={s} className="px-2 py-1 bg-blue-600/20 text-blue-400 rounded text-xs">{s}</span>)}
                        {(!user.syncedSystems || user.syncedSystems.length === 0) && <span className="text-gray-500 text-xs">Nenhum</span>}
                      </div>
                    </td>
                    <td className="px-4 py-3 text-right">
                      <button onClick={() => editUser(user)} className="text-blue-400 hover:text-blue-300 mr-3">Editar</button>
                      <button onClick={() => deleteUser(user.id)} className="text-red-400 hover:text-red-300">Excluir</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Themes Tab */}
      {activeTab === 'themes' && (
        <div className="space-y-6">
          <div className="bg-gray-800 rounded-lg p-6">
            <h3 className="text-lg font-semibold text-white mb-4">Aparência</h3>
            <div className="space-y-6">
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-3">Modo do Tema</label>
                <div className="flex space-x-4">
                  <button onClick={() => setTheme(prev => ({ ...prev, mode: 'light' }))} className={'flex-1 p-4 rounded-lg border-2 transition ' + (theme.mode === 'light' ? 'border-blue-500 bg-gray-700' : 'border-gray-600 bg-gray-700/50')}>
                    <div className="text-2xl mb-2">☀️</div>
                    <div className="text-white font-medium">Claro</div>
                  </button>
                  <button onClick={() => setTheme(prev => ({ ...prev, mode: 'dark' }))} className={'flex-1 p-4 rounded-lg border-2 transition ' + (theme.mode === 'dark' ? 'border-blue-500 bg-gray-700' : 'border-gray-600 bg-gray-700/50')}>
                    <div className="text-2xl mb-2">🌙</div>
                    <div className="text-white font-medium">Escuro</div>
                  </button>
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-3">Cor Principal</label>
                <div className="flex space-x-3">
                  {['blue', 'purple', 'green', 'red', 'orange', 'pink'].map(color => (
                    <button key={color} onClick={() => setTheme(prev => ({ ...prev, primaryColor: color }))}
                      className={'w-10 h-10 rounded-full border-2 transition ' + (theme.primaryColor === color ? 'border-white scale-110' : 'border-transparent')}
                      style={{ backgroundColor: color === 'blue' ? '#3b82f6' : color === 'purple' ? '#8b5cf6' : color === 'green' ? '#10b981' : color === 'red' ? '#ef4444' : color === 'orange' ? '#f97316' : '#ec4899' }} />
                  ))}
                </div>
              </div>
            </div>
          </div>
          <button onClick={saveThemeSettings} disabled={loading} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-lg font-medium transition">
            {loading ? 'Salvando...' : 'Salvar Configurações de Tema'}
          </button>
        </div>
      )}

      {/* AI Tab */}
      {activeTab === 'ai' && (
        <div className="space-y-6">
          <div className="bg-gray-800 rounded-lg p-6">
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center space-x-3">
                <div className="w-10 h-10 bg-purple-600 rounded-lg flex items-center justify-center"><span className="text-xl">🤖</span></div>
                <div><h3 className="text-lg font-semibold text-white">Inteligência Artificial</h3><p className="text-sm text-gray-400">Análise de infraestrutura</p></div>
              </div>
              <label className="flex items-center">
                <input type="checkbox" checked={aiSettings.enabled} onChange={(e) => setAiSettings(prev => ({ ...prev, enabled: e.target.checked }))} className="w-5 h-5 rounded bg-gray-700 border-gray-600 text-blue-600" />
                <span className="ml-2 text-gray-300">Ativar IA</span>
              </label>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-1">Provedor</label>
                <select value={aiSettings.provider} onChange={(e) => setAiSettings(prev => ({ ...prev, provider: e.target.value }))} className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500">
                  <option value="openai">OpenAI</option>
                  <option value="anthropic">Anthropic</option>
                  <option value="local">Modelo Local</option>
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-1">Modelo</label>
                <select value={aiSettings.model} onChange={(e) => setAiSettings(prev => ({ ...prev, model: e.target.value }))} className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500">
                  <option value="gpt-4">GPT-4</option>
                  <option value="gpt-4-turbo">GPT-4 Turbo</option>
                  <option value="gpt-3.5-turbo">GPT-3.5 Turbo</option>
                  <option value="claude-3">Claude 3</option>
                </select>
              </div>
            </div>
            <div className="mt-4">
              <label className="block text-sm font-medium text-gray-300 mb-1">API Key</label>
              <input type="password" value={aiSettings.apiKey} onChange={(e) => setAiSettings(prev => ({ ...prev, apiKey: e.target.value }))} placeholder="••••••••" className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500" />
            </div>
            <div className="mt-4 flex flex-wrap gap-4">
              <label className="flex items-center">
                <input type="checkbox" checked={aiSettings.autoAnalysis} onChange={(e) => setAiSettings(prev => ({ ...prev, autoAnalysis: e.target.checked }))} className="w-4 h-4 rounded bg-gray-700 border-gray-600 text-blue-600" />
                <span className="ml-2 text-gray-300">Análise automática</span>
              </label>
              <label className="flex items-center">
                <input type="checkbox" checked={aiSettings.storeKnowledge} onChange={(e) => setAiSettings(prev => ({ ...prev, storeKnowledge: e.target.checked }))} className="w-4 h-4 rounded bg-gray-700 border-gray-600 text-blue-600" />
                <span className="ml-2 text-gray-300">Armazenar conhecimento</span>
              </label>
            </div>
          </div>

          <div className="bg-gray-800 rounded-lg p-6">
            <h4 className="text-md font-semibold text-white mb-4">Consultar IA</h4>
            <div className="flex space-x-3">
              <input type="text" value={aiQuery} onChange={(e) => setAiQuery(e.target.value)} placeholder="Faça uma pergunta sobre sua infraestrutura..." className="flex-1 bg-gray-700 border border-gray-600 rounded-lg px-4 py-2 text-white focus:outline-none focus:ring-2 focus:ring-blue-500" />
              <button onClick={askAi} disabled={loading || !aiQuery.trim()} className="px-6 py-2 bg-purple-600 hover:bg-purple-500 text-white rounded-lg transition disabled:opacity-50">Perguntar</button>
            </div>
            {aiResponse && (
              <div className="mt-4 p-4 bg-gray-700/50 rounded-lg">
                <p className="text-white whitespace-pre-wrap">{aiResponse}</p>
              </div>
            )}
          </div>

          <button onClick={saveAiSettings} disabled={loading} className="w-full py-3 bg-purple-600 hover:bg-purple-500 text-white rounded-lg font-medium transition">
            {loading ? 'Salvando...' : 'Salvar Configurações de IA'}
          </button>
        </div>
      )}
    </div>
  );
};

export default Settings;
